13	/// Merge Cortex hook entries into .claude/settings.json (non-destructively).
14	fn write_claude_settings(vault_path: &Path) -> anyhow::Result<()> {
15	    let claude_dir = vault_path.join(".claude");
16	    std::fs::create_dir_all(&claude_dir)?;
17	    let settings_path = claude_dir.join("settings.json");
18	
19	    // Read existing JSON or start with empty object.
20	    let mut settings: serde_json::Value = if settings_path.exists() {
21	        let raw = std::fs::read_to_string(&settings_path)?;
22	        serde_json::from_str(&raw).unwrap_or(serde_json::json!({}))
23	    } else {
24	        serde_json::json!({})
25	    };
26	
27	    // Ensure top-level "hooks" object exists.
28	    if !settings.get("hooks").is_some_and(|v| v.is_object()) {
29	        settings["hooks"] = serde_json::json!({});
30	    }
31	    let hooks = settings["hooks"].as_object_mut().unwrap();
32	
33	    // Hook event → route mapping.
34	    let hook_entries = [
35	        ("SessionStart", "session-start"),
36	        ("UserPromptSubmit", "prompt"),
37	        ("PostToolUse", "tool-use"),
38	        ("Stop", "session-end"),
39	    ];
40	
41	    for (event, route) in hook_entries {
42	        let url = format!("http://localhost:3847/hooks/{}", route);
43	
44	        // Get or create the array for this event.
45	        if !hooks.get(event).is_some_and(|v| v.is_array()) {
